      "content": "const projects = {}; // In-memory storage for simplicity
const { randomUUID } = require('node:crypto');
const { sendError } = require('../../lib/errors');

// Get project by ID
exports.getProjectById = (req, res) => {
  const projectId = req.params.projectId;
  if (!projects[projectId]) return sendError(res, 404, 'E001', 'Project not found');
  res.json({ project: projects[projectId] });
};

// Create a new project
exports.createProject = (req, res) => {
  const { name } = req.body;
  if (!name) return sendError(res, 400, 'E002', 'Name is required');
  if (projects[name]) return sendError(res, 409, 'E003', 'Duplicate project name');
  const id = randomUUID();
  projects[id] = { id, name };
  res.status(201).json({ project: projects[id] });
};
